const items = $input.all();

let ingresos = null;
let regla = null;
let gastosFijos = null;
let compromisos = null;
let cierreMesAnterior = null;
const cuotasMap = new Map();

for (const item of items) {
  const d = item.json;

  if (d.total_usd !== undefined && ingresos === null) ingresos = d;
  if (d.regla_necesidades_pct !== undefined && regla === null) regla = d;
  if (d.total_gastos_fijos_ars !== undefined && gastosFijos === null) gastosFijos = d;
  if (d.compromisos_tc !== undefined && d.cantidad_cuotas !== undefined && compromisos === null) compromisos = d;
  if (d.gastado_deseos !== undefined && cierreMesAnterior === null) cierreMesAnterior = d;

  if (d.monto_cuota !== undefined && d.cuota_actual !== undefined && d.descripcion) {
    const key = `${d.descripcion}_${d.cuota_actual}_${d.total_cuotas}`;
    if (!cuotasMap.has(key)) cuotasMap.set(key, d);
  }
}

ingresos = ingresos || { total_usd: 0, total_ars: 0 };
regla = regla || { regla_necesidades_pct: 50, regla_deseos_pct: 30, regla_ahorro_pct: 20 };
gastosFijos = gastosFijos || { total_gastos_fijos_ars: 0, tc_usado: 1430 };
compromisos = compromisos || { compromisos_tc: 0, cantidad_cuotas: 0 };
const cuotasPorTerminar = [...cuotasMap.values()];

const fmt = n => Number(n || 0).toLocaleString('es-AR', { minimumFractionDigits: 0, maximumFractionDigits: 0 });
const TC = Number(gastosFijos.tc_usado);
const ingresoTotalArs = (Number(ingresos.total_usd) * TC) + Number(ingresos.total_ars);
const budgetNeeds = ingresoTotalArs * (Number(regla.regla_necesidades_pct) / 100);
const budgetWants = ingresoTotalArs * (Number(regla.regla_deseos_pct) / 100);
const budgetSavings = ingresoTotalArs * (Number(regla.regla_ahorro_pct) / 100);
const compromisosTc = Number(compromisos.compromisos_tc);
const disponible = Math.round(budgetWants - compromisosTc);

const now = new Date();
const yearMonth = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}`;
const mesesES = ['Enero','Febrero','Marzo','Abril','Mayo','Junio','Julio','Agosto','Septiembre','Octubre','Noviembre','Diciembre'];
const mesActual = mesesES[now.getMonth()];
const mesAnterior = mesesES[now.getMonth() === 0 ? 11 : now.getMonth() - 1];

let msg = '';
msg += `📅 *CIERRE ${mesAnterior.toUpperCase()} | INICIO ${mesActual.toUpperCase()}*\n`;
msg += `━━━━━━━━━━━━━━━━\n\n`;

if (cierreMesAnterior) {
  const gastNec = Number(cierreMesAnterior.gastado_necesidades || 0);
  const gastDes = Number(cierreMesAnterior.gastado_deseos || 0);
  const presNec = Number(cierreMesAnterior.presupuesto_necesidades || 0);
  const presDes = Number(cierreMesAnterior.presupuesto_deseos || 0);
  const totalIngreso = Number(cierreMesAnterior.ingreso_total_ars || 0);
  const totalGastado = gastNec + gastDes;
  const pctNec = presNec > 0 ? Math.round((gastNec / presNec) * 100) : 0;
  const pctDes = presDes > 0 ? Math.round((gastDes / presDes) * 100) : 0;
  const iconNec = pctNec > 100 ? '🔴' : pctNec > 85 ? '🟡' : '🟢';
  const iconDes = pctDes > 100 ? '🔴' : pctDes > 85 ? '🟡' : '🟢';
  msg += `📊 *BALANCE ${mesAnterior.toUpperCase()}*\n`;
  msg += `${iconNec} Necesidades: $${fmt(gastNec)} de $${fmt(presNec)} (${pctNec}%)\n`;
  msg += `${iconDes} Deseos: $${fmt(gastDes)} de $${fmt(presDes)} (${pctDes}%)\n`;
  const ahorro = totalIngreso - totalGastado;
  const iconAhorro = ahorro >= 0 ? '✅' : '⚠️';
  msg += `${iconAhorro} Ahorro real: *$${fmt(ahorro)}*\n\n`;
} else {
  msg += `📊 Sin datos de cierre para ${mesAnterior}\n\n`;
}

if (cuotasPorTerminar.length > 0) {
  const liberacion = cuotasPorTerminar.reduce((sum, c) => sum + Number(c.monto_cuota), 0);
  msg += `🎉 *CUOTAS POR TERMINAR*\n`;
  for (const c of cuotasPorTerminar) {
    const restantes = c.total_cuotas - c.cuota_actual;
    const texto = restantes === 0 ? 'Termina este mes' : `${restantes} mes${restantes > 1 ? 'es' : ''} más`;
    msg += `• ${c.descripcion}: $${fmt(c.monto_cuota)}/mes (${texto})\n`;
  }
  msg += `💸 Se liberan *$${fmt(liberacion)}/mes* próximamente\n\n`;
}

msg += `💰 *PRESUPUESTO ${mesActual.toUpperCase()}*\n`;
msg += `💵 Ingreso: U$D ${fmt(ingresos.total_usd)} × $${fmt(TC)} = *$${fmt(ingresoTotalArs)}*\n\n`;
msg += `📊 *Distribución 50/30/20:*\n`;
msg += `🏠 Necesidades (${regla.regla_necesidades_pct}%): $${fmt(budgetNeeds)}\n`;
msg += `🎯 Deseos (${regla.regla_deseos_pct}%): $${fmt(budgetWants)}\n`;
msg += `💎 Ahorro (${regla.regla_ahorro_pct}%): $${fmt(budgetSavings)}\n\n`;
msg += `💳 Cuotas TC (${compromisos.cantidad_cuotas} activas): $${fmt(compromisosTc)}\n`;
const iconDisp = disponible >= 0 ? '✅' : '⚠️';
msg += `${iconDisp} *Libre para gastar: $${fmt(disponible)}*\n\n`;

msg += `━━━━━━━━━━━━━━━━\n`;
msg += `🤖 Cuotas y préstamos actualizados automáticamente.\n`;
msg += `💡 _Consultame antes de gastar._`;

return {
  mensaje: msg,
  year_month: yearMonth,
  total_income_usd: Number(ingresos.total_usd),
  total_income_ars: Math.round(ingresoTotalArs),
  exchange_rate: TC,
  budget_needs: Math.round(budgetNeeds),
  budget_wants: Math.round(budgetWants),
  budget_savings: Math.round(budgetSavings),
  compromisos_tc: compromisosTc,
  disponible_para_gastar: disponible
};
